"use client";
import Image from "next/image";

interface BookingCardProps {
    bookingDate: string;
    submitDate: string;
    carProvider: string;
    carName: string;
    imgSrc: string;
    onDelete: () => void;
    onEdit: () => void;
}

export default function BookingCard({ 
    bookingDate, 
    submitDate, 
    carProvider, 
    carName,
    imgSrc, 
    onDelete, 
    onEdit 
}: BookingCardProps) {
    return (
        <div className="bg-card-bg shadow-sm overflow-hidden border border-border flex flex-col md:flex-row group hover:shadow-md transition-all duration-300">
            <div className="relative w-full md:w-80 h-64 md:h-auto overflow-hidden">
                <Image 
                    src={imgSrc} 
                    alt={carName}
                    fill
                    className="object-cover transition-transform duration-500 group-hover:scale-105"
                />
            </div>

            <div className="flex-1 p-8 md:p-12 flex flex-col justify-between">
                <div>
                    <div className="mb-8">
                        <div className="flex items-center gap-2 mb-3">
                            <span className="text-[10px] uppercase tracking-[0.3em] text-muted font-bold">Provider:</span>
                            <span className="text-[11px] uppercase tracking-[0.3em] text-accent font-bold">
                                {carProvider}
                            </span>
                        </div>
                        <h3 className="text-3xl md:text-5xl tracking-tight text-foreground leading-none font-bold">
                            {carName}
                        </h3>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8 py-8 border-y border-border">
                        <div className="space-y-2">
                            <span className="block text-[10px] uppercase tracking-[0.3em] text-muted font-bold">
                                Booking Date
                            </span>
                            <span className="text-xl text-foreground">
                                {bookingDate}
                            </span>
                        </div>
                        <div className="space-y-2">
                            <span className="block text-[10px] uppercase tracking-[0.3em] text-muted font-bold">
                                submitdate
                            </span>
                            <span className="text-xl text-muted">
                                {submitDate}
                            </span>
                        </div>
                    </div>
                </div>

                <div className="flex flex-wrap gap-4 mt-12">
                    <button 
                        onClick={onEdit}
                        className="flex-1 min-w-40 bg-accent text-white py-3 text-[11px] font-semibold uppercase tracking-[0.3em] hover:opacity-90 transition-all active:scale-[0.99] flex justify-center items-center gap-3 cursor-pointer"
                    >
                        Edit
                    </button>
                    
                    <button 
                        onClick={onDelete}
                        className="px-8 border border-border text-muted py-3 text-[11px] font-semibold uppercase tracking-[0.3em] hover:bg-red-50 hover:text-red-700 hover:border-red-100 transition-all active:scale-[0.99] flex justify-center items-center gap-3 cursor-pointer"
                    >
                        Remove
                    </button>
                </div>
            </div>
        </div>
    );
}