"use client";
import { useState } from "react";

interface EditBookingModalProps {
    isOpen: boolean;
    initialData: {
        bookingDate: string;
        carProvider: string;
        isComplete: boolean;
    };
    onClose: () => void;
    onSave: (updatedData: any) => void;
}

export default function EditBookingModal({ isOpen, initialData, onClose, onSave }: EditBookingModalProps) {
    const [bookingDate, setBookingDate] = useState(initialData.bookingDate);
    const [carProvider, setCarProvider] = useState(initialData.carProvider);
    const [isComplete, setIsComplete] = useState(initialData.isComplete);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-150 flex items-center justify-center p-6 bg-black/70 backdrop-blur-sm">
            <div className="bg-card-bg max-w-lg w-full overflow-hidden shadow-lg border border-border">
                <div className="bg-foreground p-8 text-white">
                    <h2 className="text-3xl tracking-tight font-bold">Edit Booking</h2>
                    <p className="text-[#f0e6d7] text-[10px] uppercase tracking-[0.3em] mt-2">Update reservation details</p>
                </div>

                <div className="p-10 space-y-8">
                    <div className="space-y-2">
                        <label className="block text-[10px] uppercase tracking-[0.2em] text-muted font-bold ml-2">Booking Date</label>
                        <input 
                            type="date" 
                            value={bookingDate}
                            onChange={(e) => setBookingDate(e.target.value)}
                            className="w-full bg-card-bg border border-border px-6 py-4 outline-none focus:border-accent focus:ring-1 focus:ring-accent transition-all text-sm text-foreground font-semibold"
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="block text-[10px] uppercase tracking-[0.2em] text-muted font-bold ml-2">Provider Name</label>
                        <input 
                            type="text" 
                            value={carProvider}
                            onChange={(e) => setCarProvider(e.target.value)}
                            placeholder="Enter Provider Name"
                            className="w-full bg-card-bg border border-border px-6 py-4 outline-none focus:border-accent focus:ring-1 focus:ring-accent transition-all text-sm text-foreground font-semibold placeholder:text-muted"
                        />
                    </div>

                    <div className="flex items-center justify-between px-2">
                        <span className="text-[10px] uppercase tracking-[0.2em] text-muted font-bold">Booking Status</span>
                        <label className="relative inline-flex items-center cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={isComplete}
                                onChange={(e) => setIsComplete(e.target.checked)}
                                className="sr-only peer" 
                            />
                            <div className="w-14 h-7 bg-[#d8cfc1] peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full rtl:peer-checked:after:-translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-0.5 after:inset-s-0.5 after:bg-white after:border-border after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-accent"></div>
                            <span className="ml-3 text-[10px] uppercase tracking-widest text-foreground font-bold">
                                {isComplete ? "Complete" : "Pending"}
                            </span>
                        </label>
                    </div>

                    <div className="flex gap-4 pt-4">
                        <button 
                            onClick={onClose}
                            className="flex-1 border border-border text-foreground py-3 text-[10px] font-semibold uppercase tracking-[0.2em] hover:bg-[#f4efe8] transition-all active:scale-[0.99] cursor-pointer"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={() => onSave({ bookingDate, carProvider, isComplete })}
                            className="flex-1 bg-accent text-white py-3 text-[10px] font-semibold uppercase tracking-[0.2em] hover:opacity-90 transition-all shadow-sm active:scale-[0.99] cursor-pointer"
                        >
                            Save Changes
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}