"use client";
import { useState } from "react";
import BookingCard from "@/components/BookingCard";
import EditBookingModal from "@/components/EditBookingModal";

export default function MyBookingsPage() {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedBooking, setSelectedBooking] = useState<any>(null);

    const [myBookings, setMyBookings] = useState([
        {
            id: "BK-001",
            carName: "Rolls-Royce Ghost",
            carProvider: "Elite Heritage Fleet",
            bookingDate: "2026-06-12",
            submitDate: "01 June 2026",
            imgSrc: "/img/img3.jpg",
            isComplete: false
        },
        {
            id: "BK-002",
            carName: "Bentley Bentayga",
            carProvider: "Royal Velvet Motors",
            bookingDate: "2026-07-15",
            submitDate: "10 June 2026",
            imgSrc: "/img/img4.jpg",
            isComplete: true
        }
    ]);

    const handleOpenEdit = (booking: any) => {
        setSelectedBooking(booking);
        setIsModalOpen(true);
    };

    const handleSaveEdit = (updatedFields: any) => {
        setMyBookings(myBookings.map(b => 
            b.id === selectedBooking.id ? { ...b, ...updatedFields } : b
        ));
        setIsModalOpen(false);
    };

    const handleRemove = (id: string) => {
        setMyBookings(myBookings.filter(b => b.id !== id));
    };

    return (
        <main className="min-h-screen bg-background">
            <div className="bg-foreground pt-24 pb-20 px-6 md:px-8">
                <div className="max-w-6xl mx-auto flex justify-between items-end">
                    <div>
                        <p className="text-xs uppercase tracking-[0.3rem] text-[#f0e6d7] mb-2">マイ ブッキング</p>
                        <h1 className="text-4xl md:text-6xl text-white tracking-tight mb-4 leading-none font-bold">
                            My Bookings
                        </h1>
                        <p className="text-[#f0e6d7] text-[10px] uppercase tracking-[0.35em]">
                            Reservation Management System
                        </p>
                        <div className="w-10 h-0.5 bg-accent mt-4" />
                    </div>
                </div>
            </div>

            <div className="max-w-6xl mx-auto px-6 md:px-8 -mt-10 pb-24">
                <div className="grid grid-cols-1 gap-12">
                    {myBookings.length > 0 ? (
                        myBookings.map((booking) => (
                            <div key={booking.id} className="relative">
                                <BookingCard
                                    carName={booking.carName}
                                    carProvider={booking.carProvider}
                                    bookingDate={booking.bookingDate}
                                    submitDate={booking.submitDate}
                                    imgSrc={booking.imgSrc}
                                    onEdit={() => handleOpenEdit(booking)}
                                    onDelete={() => handleRemove(booking.id)}
                                />
                                {booking.isComplete && (
                                    <div className="absolute top-6 right-6 bg-accent text-white text-[8px] uppercase tracking-[0.2em] font-bold px-4 py-1 shadow-sm">
                                        Completed
                                    </div>
                                )}
                            </div>
                        ))
                    ) : (
                        <div className="bg-card-bg p-20 text-center border border-border shadow-sm flex flex-col items-center">
                            <h3 className="text-4xl text-muted mb-8">No Active Bookings</h3>
                            <button className="bg-accent text-white px-10 py-3 text-[11px] uppercase tracking-[0.3em] hover:opacity-90 transition-all cursor-pointer">
                                New Booking
                            </button>
                        </div>
                    )}
                </div>
            </div>

            {selectedBooking && (
                <EditBookingModal
                    isOpen={isModalOpen}
                    initialData={{
                        bookingDate: selectedBooking.bookingDate,
                        carProvider: selectedBooking.carProvider,
                        isComplete: selectedBooking.isComplete
                    }}
                    onClose={() => setIsModalOpen(false)}
                    onSave={handleSaveEdit}
                />
            )}
        </main>
    );
}